mapper.sql:
FROM sys_search_document
WHERE status = 1 AND is_deleted = 0



    AND stage_key = #{q.stageKey}


    AND channel_key = #{q.channelKey}


    AND resource_type_name = #{q.teachingType}

mapper.select:
SELECT * FROM sys_search_document WHERE status = 1 AND is_deleted = 0
AND vip_flag = 0
AND doc_type IN
#{dt}
AND ( title LIKE CONCAT('%', #{q.rawKeyword}, '%') OR keyword_text LIKE CONCAT('%', #{q.rawKeyword}, '%') OR summary LIKE CONCAT('%', #{q.rawKeyword}, '%') )
ORDER BY CASE WHEN title LIKE CONCAT(#{q.rawKeyword}, '%') THEN 0 ELSE 1 END, hot_score DESC LIMIT #{q.limit}
